import{_ as a,H as n,f as t,i as p}from"./chunks/framework.BHvCMIhP.js";const u=JSON.parse('{"title":"构建次数与运行时间:CI/CD、Pages、Serverless 的隐形限制","description":"","frontmatter":{},"headers":[],"relativePath":"cloudBasicsLearning/38-构建次数与运行时间.md","filePath":"cloudBasicsLearning/38-构建次数与运行时间.md","lastUpdated":1779015580000}'),e={name:"cloudBasicsLearning/38-构建次数与运行时间.md"};function l(i,s,d,r,c,o){return n(),t("div",null,[...s[0]||(s[0]=[p(`<h1 id="构建次数与运行时间-ci-cd、pages、serverless-的隐形限制" tabindex="-1">构建次数与运行时间:CI/CD、Pages、Serverless 的隐形限制 <a class="header-anchor" href="#构建次数与运行时间-ci-cd、pages、serverless-的隐形限制" aria-label="Permalink to &quot;构建次数与运行时间:CI/CD、Pages、Serverless 的隐形限制&quot;">​</a></h1><h2 id="一句话解释" tabindex="-1">一句话解释 <a class="header-anchor" href="#一句话解释" aria-label="Permalink to &quot;一句话解释&quot;">​</a></h2><p><strong>构建次数和运行时间,是在数你的代码被平台构建了多少次、构建用了多久,以及运行时代码实际执行了多久</strong>。</p><p>它最容易和&quot;部署成功&quot;混淆。很多平台把流程包装得很简单:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>git push</span></span>
<span class="line"><span>  -&gt; 自动构建</span></span>
<span class="line"><span>  -&gt; 自动部署</span></span>
<span class="line"><span>  -&gt; 自动预览</span></span></code></pre></div><p>但自动不代表没有成本。安装依赖、编译、测试、生成静态页面、优化图片、上传构建产物,都会消耗构建资源。Serverless 函数、边缘函数、后台任务、定时任务虽然不用你管理服务器,但每次执行也会消耗运行时间和调用额度。</p><p>一句话先记住:<strong>CI/CD 消耗的是构建资源,Serverless 消耗的是运行资源,两者都可能成为免费套餐里的隐形上限</strong>。</p><h2 id="放在系统哪里" tabindex="-1">放在系统哪里 <a class="header-anchor" href="#放在系统哪里" aria-label="Permalink to &quot;放在系统哪里&quot;">​</a></h2><p>构建次数和运行时间分别发生在两个阶段。</p><p>第一阶段是交付阶段:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>开发者提交代码</span></span>
<span class="line"><span>  -&gt; Git 平台触发 webhook</span></span>
<span class="line"><span>  -&gt; CI/CD 拉取代码</span></span>
<span class="line"><span>  -&gt; 安装依赖</span></span>
<span class="line"><span>  -&gt; 运行测试</span></span>
<span class="line"><span>  -&gt; 执行 build</span></span>
<span class="line"><span>  -&gt; 上传产物</span></span>
<span class="line"><span>  -&gt; 部署到 Pages / CDN / 容器 / 函数平台</span></span></code></pre></div><p>这里消耗的是构建次数、构建分钟、构建并发、缓存容量、产物存储、预览部署数量。</p><p>第二阶段是运行阶段:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>用户请求</span></span>
<span class="line"><span>  -&gt; CDN</span></span>
<span class="line"><span>  -&gt; Serverless / Edge Function / API Route</span></span>
<span class="line"><span>  -&gt; 数据库 / 对象存储 / 第三方 API</span></span>
<span class="line"><span>  -&gt; 返回响应</span></span></code></pre></div><p>这里消耗的是函数调用次数、执行时间、内存、CPU 时间、并发、超时时间、后台任务运行时间。</p><p>现代前端平台经常把这两个阶段放在一个产品里。例如 Pages、Vercel、Netlify、Cloudflare、Firebase、Supabase Edge Functions 这类平台,既可能帮你构建前端,也可能运行函数。于是小团队很容易以为&quot;网站托管是免费的&quot;,却忽略了:</p><ul><li>每次 push 都会触发构建.</li><li>每个 pull request 都可能生成预览环境.</li><li>每次构建都安装依赖和生成页面.</li><li>SSR 页面每次访问都可能运行函数.</li><li>定时任务即使没人访问也会运行.</li><li>失败构建和失败任务同样消耗额度.</li></ul><h2 id="常见套餐和使用限制" tabindex="-1">常见套餐和使用限制 <a class="header-anchor" href="#常见套餐和使用限制" aria-label="Permalink to &quot;常见套餐和使用限制&quot;">​</a></h2><p>构建相关限制通常包括:</p><table tabindex="0"><thead><tr><th>限制项</th><th>含义</th><th>常见风险</th></tr></thead><tbody><tr><td>构建分钟</td><td>构建任务占用执行器的时间</td><td>依赖安装慢、静态页面多、测试慢</td></tr><tr><td>构建次数</td><td>每月或每日可触发多少次构建</td><td>频繁 push、多分支预览</td></tr><tr><td>构建并发</td><td>同时能跑几个构建</td><td>多人提交时排队</td></tr><tr><td>构建超时</td><td>单次构建最长能跑多久</td><td>大项目或卡住的脚本失败</td></tr><tr><td>缓存容量</td><td>node_modules、构建缓存、测试缓存</td><td>缓存失效导致每次全量安装</td></tr><tr><td>预览部署</td><td>PR 或分支预览环境数量</td><td>分支不清理,占用额度</td></tr><tr><td>产物大小</td><td>build 输出文件大小</td><td>大文件、source map、图片混入产物</td></tr></tbody></table><p>运行相关限制通常包括:</p><table tabindex="0"><thead><tr><th>限制项</th><th>含义</th><th>常见风险</th></tr></thead><tbody><tr><td>调用次数</td><td>函数被触发多少次</td><td>API 太碎、爬虫、轮询</td></tr><tr><td>执行时间</td><td>函数从开始到结束用了多久</td><td>慢查询、第三方 API 慢</td></tr><tr><td>最大时长</td><td>单次函数最多运行多久</td><td>文件处理、AI 调用、批任务超时</td></tr><tr><td>内存</td><td>函数可用内存</td><td>图片处理、PDF 生成、批量数据</td></tr><tr><td>并发</td><td>同时运行多少个实例</td><td>流量突增时排队或失败</td></tr><tr><td>冷启动</td><td>空闲后首次启动延迟</td><td>低频接口偶发变慢</td></tr><tr><td>定时任务次数</td><td>cron 或 scheduled job 触发次数</td><td>任务频率过高</td></tr></tbody></table><p>免费套餐里,这些限制经常不是单独出现,而是组合出现:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>构建分钟用完 -&gt; 新版本无法自动发布</span></span>
<span class="line"><span>构建并发不足 -&gt; 多人提交排队</span></span>
<span class="line"><span>函数调用超额 -&gt; 开始计费或拒绝请求</span></span>
<span class="line"><span>函数执行超时 -&gt; 用户看到 504 或任务失败</span></span>
<span class="line"><span>内存不足 -&gt; 图片处理、PDF 生成直接崩溃</span></span>
<span class="line"><span>后台任务无限重试 -&gt; 同时消耗调用次数和运行时间</span></span></code></pre></div><p>看套餐时,要专门确认四件事。</p><p>第一,构建是否按分钟、次数还是并发限制。有的平台主要限制总分钟,有的平台更关注并发和队列,有的平台对团队协作和预览部署另算。</p><p>第二,失败是否计入用量。多数情况下,失败构建、失败测试、失败函数、超时任务也会消耗资源。一个错误配置的构建脚本如果反复触发,可能没有成功发布任何东西,却消耗了大量额度。</p><p>第三,预览环境是否消耗额度。PR 预览很好用,但每个分支都自动构建,会把个人项目变成持续消耗构建分钟的机器。多人小团队尤其要注意。</p><p>第四,运行时限制是否适合业务。短 API 可以放 Serverless,长时间导入、视频处理、批量邮件、爬虫任务、AI 批处理未必适合放在短超时函数里。强行放进去,不是省服务器,而是把失败和重试转移到账单里。</p><p>查看方法上,至少看:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Deployments:每次构建耗时和失败原因</span></span>
<span class="line"><span>Build logs:时间花在依赖安装、测试还是生成页面</span></span>
<span class="line"><span>Usage:构建分钟、函数调用、运行时间</span></span>
<span class="line"><span>Functions:每个函数的调用量、耗时、错误率</span></span>
<span class="line"><span>Cron / Jobs:定时任务频率和执行结果</span></span>
<span class="line"><span>Billing details:超额后是计费、限速还是暂停</span></span></code></pre></div><h2 id="小团队建议" tabindex="-1">小团队建议 <a class="header-anchor" href="#小团队建议" aria-label="Permalink to &quot;小团队建议&quot;">​</a></h2><p>小团队要把构建和运行分开治理。</p><p>构建侧先做这些事:</p><ul><li>不要每个无关分支都自动部署生产级预览.</li><li>合理使用构建缓存,避免每次全量安装依赖.</li><li>把慢测试分层,提交时跑关键测试,定时或合并前跑完整测试.</li><li>静态页面数量很大时,评估增量构建或按需生成.</li><li>source map、大图片、临时文件不要无意进入产物.</li><li>删除长期不用的预览环境和旧部署.</li><li>构建失败要停止循环触发,不要让机器人反复提交或重跑.</li></ul><p>运行侧重点是把短请求和长任务分开:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>适合 Serverless:</span></span>
<span class="line"><span>  - 登录回调</span></span>
<span class="line"><span>  - 表单提交</span></span>
<span class="line"><span>  - 短 API</span></span>
<span class="line"><span>  - webhook 处理</span></span>
<span class="line"><span>  - 轻量数据转换</span></span>
<span class="line"><span></span></span>
<span class="line"><span>不适合直接放短超时 Serverless:</span></span>
<span class="line"><span>  - 大文件转码</span></span>
<span class="line"><span>  - 长时间爬虫</span></span>
<span class="line"><span>  - 大批量数据导入</span></span>
<span class="line"><span>  - 长时间 AI 任务</span></span>
<span class="line"><span>  - 需要稳定连接的实时服务</span></span></code></pre></div><p>不适合 Serverless 的任务,可以考虑队列加 worker、容器任务、定时批处理、专门的后台服务。判断标准不是&quot;能不能跑起来&quot;,而是&quot;失败后能不能恢复,重试会不会放大成本,最长时间是否超过平台限制&quot;。</p><p>对预算护栏,建议至少设置:</p><ul><li>构建分钟接近上限提醒.</li><li>单次构建耗时异常提醒.</li><li>函数调用次数异常增长提醒.</li><li>函数平均耗时和超时率提醒.</li><li>定时任务失败重试次数提醒.</li><li>月度账单和用量预算提醒.</li></ul><p>对工程流程,建议有三个小规则:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>1. main 分支才自动生产部署</span></span>
<span class="line"><span>2. PR 预览按需开启或定期清理</span></span>
<span class="line"><span>3. 后台任务必须有最大运行时间、最大重试次数和幂等设计</span></span></code></pre></div><p>另外,不要把构建平台当成通用计算平台。有些人会用 CI 去跑爬虫、批量转码、数据同步、定时脚本。短期看方便,长期看会挤占构建额度,也会让发布流程和后台任务互相影响。CI 的主要职责是交付代码,不是承载全部后台计算。</p><p>一个保守原则是:<strong>构建资源保障发布,运行资源保障用户请求,后台长任务要有自己的队列和停止条件</strong>。</p><h2 id="一句话总结" tabindex="-1">一句话总结 <a class="header-anchor" href="#一句话总结" aria-label="Permalink to &quot;一句话总结&quot;">​</a></h2><p><strong>构建次数和运行时间是自动部署时代最容易被忽略的成本维度;push、预览、测试、SSR、函数和定时任务都会消耗额度,必须设置用量告警和停止条件</strong>。</p>`,46)])])}const g=a(e,[["render",l]]);export{u as __pageData,g as default};
